function braceSlice(src: string, startMarker: string, stmt = false): string {
  const i = src.indexOf(startMarker);
  if (i < 0) throw new Error(`marker not found: ${startMarker}`);
  let d = 0;
  for (let j = src.indexOf('{', i); j < src.length; j++) {
